// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertInstanceOf;

import java.util.List;

import org.junit.jupiter.api.Test;

class RequiredPhysicalPropertiesTest {

	@Test
	void oppositeOrderingDirectionsReportConflict() {
		BindingSymbol value = BindingUniverse.create().symbol("value");
		RequiredPhysicalProperties ascending = RequiredPhysicalProperties.builder()
				.ordering(List.of(SortKey.of(value, SortKey.Direction.ASC)))
				.build();
		RequiredPhysicalProperties descending = RequiredPhysicalProperties.builder()
				.ordering(List.of(SortKey.of(value, SortKey.Direction.DESC)))
				.build();

		RequiredPhysicalProperties.Intersection result = ascending.intersect(descending);

		RequiredPhysicalProperties.Conflict conflict = assertInstanceOf(
				RequiredPhysicalProperties.Conflict.class, result);
		assertEquals(RequiredPhysicalProperties.ConflictProperty.ORDERING, conflict.property());
	}

	@Test
	void compatibleOrderingIntersectionKeepsLongerPrefix() {
		BindingUniverse universe = BindingUniverse.create();
		SortKey first = SortKey.ascending(universe.symbol("first"));
		SortKey second = SortKey.descending(universe.symbol("second"));
		RequiredPhysicalProperties prefix = RequiredPhysicalProperties.builder()
				.ordering(List.of(first))
				.build();
		RequiredPhysicalProperties longer = RequiredPhysicalProperties.builder()
				.ordering(List.of(first, second))
				.build();

		RequiredPhysicalProperties.Intersection result = prefix.intersect(longer);

		RequiredPhysicalProperties.Compatible compatible = assertInstanceOf(
				RequiredPhysicalProperties.Compatible.class, result);
		assertEquals(List.of(first, second), compatible.properties().ordering());
	}

	@Test
	void streamingAndMaterializedRequirementsConflict() {
		RequiredPhysicalProperties streaming = RequiredPhysicalProperties.builder()
				.materialization(RequiredPhysicalProperties.Materialization.STREAMING)
				.build();
		RequiredPhysicalProperties materialized = RequiredPhysicalProperties.builder()
				.materialization(RequiredPhysicalProperties.Materialization.MATERIALIZED)
				.build();

		RequiredPhysicalProperties.Intersection result = streaming.intersect(materialized);

		RequiredPhysicalProperties.Conflict conflict = assertInstanceOf(
				RequiredPhysicalProperties.Conflict.class, result);
		assertEquals(RequiredPhysicalProperties.ConflictProperty.MATERIALIZATION, conflict.property());
	}

	@Test
	void compatibleRequirementsUnionBindingMasks() {
		BindingUniverse universe = BindingUniverse.create();
		RequiredPhysicalProperties left = RequiredPhysicalProperties.builder()
				.distinctBindings(universe.maskOf(List.of("left")))
				.parameterBindings(universe.maskOf(List.of("outerLeft")))
				.build();
		RequiredPhysicalProperties right = RequiredPhysicalProperties.builder()
				.distinctBindings(universe.maskOf(List.of("right")))
				.parameterBindings(universe.maskOf(List.of("outerRight")))
				.build();

		RequiredPhysicalProperties.Compatible result = assertInstanceOf(RequiredPhysicalProperties.Compatible.class,
				left.intersect(right));

		assertEquals(universe.maskOf(List.of("left", "right")), result.properties().distinctBindings());
		assertEquals(universe.maskOf(List.of("outerLeft", "outerRight")),
				result.properties().parameterBindings());
	}

	@Test
	void differentPhysicalOperatorsConflict() {
		RequiredPhysicalProperties left = RequiredPhysicalProperties.builder()
				.operator(PhysicalOperatorId.of("index-scan"))
				.build();
		RequiredPhysicalProperties right = RequiredPhysicalProperties.builder()
				.operator(PhysicalOperatorId.of("table-scan"))
				.build();

		RequiredPhysicalProperties.Conflict conflict = assertInstanceOf(RequiredPhysicalProperties.Conflict.class,
				left.intersect(right));

		assertEquals(RequiredPhysicalProperties.ConflictProperty.OPERATOR, conflict.property());
	}
}
